CREATE TABLE uuid_ids ( id uuid, title text, tag string, price int );
CREATE TABLE uuid_auto ( id uuid, title text, tag string, price int );
CREATE TABLE uuid_col ( id uuid, title text, tag string, price int ) engine='columnar';
CREATE TABLE uuid_case ( id uuid, title text, tag string, price int );
CREATE TABLE uuid_txn ( id uuid, title text, tag string );
